pub fn irqIndex(comptime name: [:0]const u8) comptime_int {
    for (interrupts) |entry| {
        if (entry.name.len != name.len) continue;
        var match = true;
        for (entry.name, name) |a, b| {
            if (a != b) {
                match = false;
                break;
            }
        }
        if (match) return entry.index;
    }
    @compileError("unknown interrupt: " ++ name);
}

