pub const cc: std.builtin.CallingConvention = .{ .arm_aapcs = .{} };
pub const Handler = *const fn () callconv(cc) void;
pub const unhandled: Handler = &defaultHandler;
fn defaultHandler() callconv(cc) void {
    while (true) {}
}

